f = open('ai-career-login.html', 'w', encoding='utf-8')
f.write("<!DOCTYPE html><html lang=\"zh-CN\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1.0\"><title>Future Career</title><style>")
f.write("* { margin: 0; padding: 0; box-sizing: border-box; } body { min-height: 100vh; background: #050815; font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif; overflow: hidden; } .bg-container { position: fixed; top: 0; left: 0; width: 100%; height: 100%; z-index: 0; background: linear-gradient(180deg, #050815 0%, #0a0e25 50%, #0f1430 100%); } #star-canvas { position: absolute; top: 0; left: 0; width: 100%; height: 100%; }")
f.write(".main-content { position: relative; z-index: 1; display: flex; align-items: center; justify-content: center; min-height: 100vh; padding: 40px; } .wrapper { display: flex; gap: 80px; max-width: 1400px; width: 100%; align-items: center; }")
f.write(".left-section { flex: 1; display: flex; flex-direction: column; align-items: center; position: relative; } .brand { position: absolute; top: -60px; left: 0; display: flex; align-items: center; gap: 8px; } .brand-title { font-size: 16px; font-weight: 600; color: #00d4ff; letter-spacing: 1px; } .brand-dot { color: rgba(255,255,255,0.3); font-size: 14px; } .brand-sub { font-size: 11px; color: rgba(255,255,255,0.4); }")
f.write(".globe-box { margin-bottom: 50px; } .globe { width: 280px; height: 280px; } .title-area { text-align: center; margin-bottom: 60px; } .title { display: flex; gap: 8px; margin-bottom: 15px; justify-content: center; } .title-char { font-size: 48px; font-weight: bold; background: linear-gradient(135deg, #00d4ff, #a855f7); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; text-shadow: 0 0 40px rgba(0,212,255,0.5); } .subtitle { font-size: 14px; color: rgba(255,255,255,0.5); letter-spacing: 12px; }")
f.write(".guest-btn { padding: 12px 55px; background: transparent; border: 1px solid rgba(0,212,255,0.5); border-radius: 25px; color: #00d4ff; font-size: 14px; cursor: pointer; transition: all 0.3s ease; position: absolute; bottom: -80px; } .guest-btn:hover { background: rgba(0,212,255,0.1); border-color: #00d4ff; box-shadow: 0 0 30px rgba(0,212,255,0.3); }")
f.write(".right-section { flex: 1; display: flex; justify-content: center; } .login-card { width: 100%; max-width: 420px; background: rgba(25, 20, 50, 0.6); border-radius: 16px; padding: 50px 45px; position: relative; backdrop-filter: blur(20px); border: 1px solid rgba(255,255,255,0.05); }")
f.write(".card-border { position: absolute; top: 0; left: 0; right: 0; bottom: 0; pointer-events: none; } .corner-line { position: absolute; width: 40px; height: 40px; border: 1px solid; } .cl-tl { top: 12px; left: 12px; border-right: none; border-bottom: none; border-color: #00d4ff; box-shadow: 0 0 15px rgba(0,212,255,0.5); } .cl-tr { top: 12px; right: 12px; border-left: none; border-bottom: none; border-color: #a855f7; box-shadow: 0 0 15px rgba(168,85,247,0.5); } .cl-bl { bottom: 12px; left: 12px; border-right: none; border-top: none; border-color: #a855f7; box-shadow: 0 0 15px rgba(168,85,247,0.5); } .cl-br { bottom: 12px; right: 12px; border-left: none; border-top: none; border-color: #00d4ff; box-shadow: 0 0 15px rgba(0,212,255,0.5); }")
f.write(".card-header { text-align: center; margin-bottom: 35px; } .tabs { display: flex; align-items: center; justify-content: center; gap: 12px; margin-bottom: 20px; } .tab { padding: 6px 18px; background: rgba(0,212,255,0.08); border: 1px solid rgba(0,212,255,0.2); border-radius: 15px; font-size: 12px; color: #00d4ff; cursor: pointer; display: flex; align-items: center; gap: 6px; } .tab:before { content: \"◎\"; font-size: 8px; opacity: 0.6; } .tab.active { background: rgba(0,212,255,0.18); border-color: rgba(0,212,255,0.4); } .tab-more { color: rgba(255,255,255,0.3); font-size: 14px; margin-left: 5px; } .card-title { font-size: 28px; font-weight: bold; color: #fff; margin-bottom: 8px; } .card-sub { font-size: 13px; color: rgba(255,255,255,0.4); }")
f.write(".login-form { display: flex; flex-direction: column; gap: 22px; } .input-group { position: relative; } .input-wrap { position: relative; background: rgba(255,255,255,0.03); border-radius: 10px; border: 1px solid rgba(255,255,255,0.15); transition: all 0.3s ease; } .input-wrap:focus-within { border-color: rgba(0,212,255,0.4); box-shadow: 0 0 20px rgba(0,212,255,0.1); } .field-icon { position: absolute; left: 20px; top: 50%; transform: translateY(-50%); font-size: 18px; color: rgba(255,255,255,0.4); z-index: 1; } .input-field { width: 100%; padding: 16px 16px 16px 55px; background: transparent; border: none; border-radius: 10px; color: #fff; font-size: 15px; outline: none; } .input-field::placeholder { color: rgba(255,255,255,0.3); } .forgot-password { position: absolute; right: 0; bottom: -26px; font-size: 12px; color: rgba(255,255,255,0.5); text-decoration: none; }")
f.write(".form-options { display: flex; justify-content: space-between; align-items: center; margin-top: 8px; } .remember-me { display: flex; align-items: center; gap: 8px; cursor: pointer; } .remember-me input { display: none; } .remember-box { width: 16px; height: 16px; border: 1px solid rgba(255,255,255,0.3); border-radius: 50%; position: relative; } .remember-me input:checked + .remember-box { background: rgba(0,212,255,0.2); border-color: #00d4ff; } .remember-me input:checked + .remember-box:after { content: \"\"; position: absolute; top: 4px; left: 4px; width: 6px; height: 6px; background: #00d4ff; border-radius: 50%; } .remember-text { font-size: 13px; color: rgba(255,255,255,0.5); } .quick-guest-btn { padding: 7px 20px; background: rgba(168,85,247,0.15); border: 1px solid rgba(168,85,247,0.3); border-radius: 15px; color: #a855f7; font-size: 12px; cursor: pointer; }")
f.write(".login-btn { width: 100%; padding: 17px; margin-top: 5px; background: linear-gradient(135deg, #00d4ff, #a855f7); border: none; border-radius: 10px; color: #fff; font-size: 16px; font-weight: bold; cursor: pointer; letter-spacing: 2px; } .login-btn:hover { transform: translateY(-2px); box-shadow: 0 10px 35px rgba(0,212,255,0.4), 0 10px 35px rgba(168,85,247,0.3); }")
f.write(".divider { display: flex; align-items: center; gap: 15px; margin: 30px 0; } .divider-line { flex: 1; height: 1px; background: rgba(255,255,255,0.08); } .divider-text { font-size: 12px; color: rgba(255,255,255,0.4); } .social-login { display: flex; justify-content: center; gap: 20px; } .social-btn { width: 48px; height: 48px; border-radius: 50%; background: rgba(0,0,0,0.3); border: 1px solid rgba(255,255,255,0.1); display: flex; align-items: center; justify-content: center; font-size: 22px; cursor: pointer; } .social-btn:hover { background: rgba(0,212,255,0.15); border-color: rgba(0,212,255,0.4); }")
